<script setup lang="ts">
import type { ReportBlock } from '../../shared/contracts'
interface Props{block:ReportBlock;selected:boolean;index:number;total:number}interface Emits{select:[id:string];update:[block:ReportBlock];move:[id:string,direction:-1|1];remove:[id:string];chooseImage:[id:string]}
const props=defineProps<Props>();const emit=defineEmits<Emits>();function patch(value:Partial<ReportBlock>){emit('update',{...props.block,...value})}function patchStyle(value:Partial<ReportBlock['style']>){patch({style:{...props.block.style,...value}})}function patchLayout(value:Partial<ReportBlock['layout']>){patch({layout:{...props.block.layout,...value}})}
</script>
<template><v-hover v-slot="{isHovering,props:hoverProps}"><v-card v-bind="hoverProps" variant="outlined" class="module-card pa-4" :class="{'is-hovered':isHovering,'border-primary':selected}" @click="emit('select',block.id)"><div class="d-flex align-center justify-space-between"><div class="d-flex align-center ga-2"><v-icon :icon="block.type==='heading'?'mdi-format-header-pound':block.type==='rich-text'?'mdi-text-box-outline':block.type==='image'||block.type==='atlas-page'?'mdi-image-outline':block.type==='statistics'?'mdi-chart-box-outline':'mdi-information-outline'" color="primary"/><div class="font-weight-bold">{{ block.type }}</div><v-chip size="x-small" variant="outlined">page {{ block.layout.page }}</v-chip><v-chip size="x-small" variant="outlined">{{ block.layout.mode }}</v-chip></div><div class="d-flex"><v-btn icon="mdi-arrow-up" size="x-small" variant="text" :disabled="index===0" @click.stop="emit('move',block.id,-1)"/><v-btn icon="mdi-arrow-down" size="x-small" variant="text" :disabled="index===total-1" @click.stop="emit('move',block.id,1)"/><v-btn icon="mdi-delete-outline" size="x-small" variant="text" color="error" @click.stop="emit('remove',block.id)"/></div></div><v-expand-transition><div v-if="selected" class="mt-4" @click.stop><v-textarea v-if="['heading','rich-text','callout'].includes(block.type)" :model-value="block.text" label="Content" auto-grow rows="2" @update:model-value="patch({text:String($event)})"/><template v-if="block.type==='image'||block.type==='atlas-page'"><v-text-field :model-value="block.imagePath" label="Image path" readonly prepend-inner-icon="mdi-image-outline"><template #append-inner><v-btn icon="mdi-file-image-search-outline" size="small" variant="text" color="primary" @click="emit('chooseImage',block.id)"/></template></v-text-field><v-text-field :model-value="block.caption" label="Caption" @update:model-value="patch({caption:String($event)})"/><v-select :model-value="block.imageFit??'contain'" label="Image fit" :items="['contain','cover']" @update:model-value="patch({imageFit:$event as 'contain'|'cover'})"/></template><template v-if="block.type==='statistics'"><v-textarea :model-value="(block.statistics??[]).map(item=>`${item.label}: ${item.value}`).join('\n')" label="One Label: Value per line" rows="4" @update:model-value="patch({statistics:String($event).split('\n').filter(Boolean).map(line=>{const [label,...rest]=line.split(':');return{label:label.trim(),value:rest.join(':').trim()}})})"/></template><v-row><v-col cols="6" md="3"><v-select :model-value="block.style.fontFamily" label="Font" :items="['sans','serif','mono']" @update:model-value="patchStyle({fontFamily:$event as ReportBlock['style']['fontFamily']})"/></v-col><v-col cols="6" md="3"><v-text-field :model-value="block.style.fontSize" type="number" label="Size" @update:model-value="patchStyle({fontSize:Number($event)})"/></v-col><v-col cols="6" md="3"><v-select :model-value="block.style.alignment" label="Align" :items="['left','center','right','justify']" @update:model-value="patchStyle({alignment:$event as ReportBlock['style']['alignment']})"/></v-col><v-col cols="6" md="3"><v-text-field :model-value="block.style.color" type="color" label="Color" @update:model-value="patchStyle({color:String($event)})"/></v-col></v-row><div class="d-flex flex-wrap ga-2 mb-4"><v-btn :color="block.style.fontWeight>=700?'primary':undefined" :variant="block.style.fontWeight>=700?'tonal':'text'" icon="mdi-format-bold" size="small" @click="patchStyle({fontWeight:block.style.fontWeight>=700?400:700})"/><v-btn :color="block.style.italic?'primary':undefined" :variant="block.style.italic?'tonal':'text'" icon="mdi-format-italic" size="small" @click="patchStyle({italic:!block.style.italic})"/><v-btn :color="block.style.underline?'primary':undefined" :variant="block.style.underline?'tonal':'text'" icon="mdi-format-underline" size="small" @click="patchStyle({underline:!block.style.underline})"/><v-switch :model-value="block.layout.mode==='freeform'" label="Freeform" color="secondary" hide-details @update:model-value="patchLayout({mode:$event?'freeform':'structured'})"/></div><v-row><v-col cols="4" md="2"><v-text-field :model-value="block.layout.page" type="number" min="1" label="Page" @update:model-value="patchLayout({page:Math.max(1,Number($event))})"/></v-col><v-col v-if="block.layout.mode==='structured'" cols="4" md="2"><v-select :model-value="block.layout.span" label="Columns" :items="[1,2]" @update:model-value="patchLayout({span:Number($event) as 1|2})"/></v-col><template v-else><v-col cols="4" md="2"><v-text-field :model-value="block.layout.x" type="number" label="X %" @update:model-value="patchLayout({x:Number($event)})"/></v-col><v-col cols="4" md="2"><v-text-field :model-value="block.layout.y" type="number" label="Y %" @update:model-value="patchLayout({y:Number($event)})"/></v-col><v-col cols="4" md="2"><v-text-field :model-value="block.layout.width" type="number" label="W %" @update:model-value="patchLayout({width:Number($event)})"/></v-col><v-col cols="4" md="2"><v-text-field :model-value="block.layout.height" type="number" label="H %" @update:model-value="patchLayout({height:Number($event)})"/></v-col></template></v-row></div></v-expand-transition></v-card></v-hover></template>
